INSERT INTO packages (id, slug, name, tagline, description, tags, inclusions, capacity, space_requirement, starting_price_cents, price_is_placeholder, damage_deposit_cents, bundle_discount, featured, sort_order, created_at, updated_at) VALUES (1, 'tent-sleepover', 'Tent Sleepover', 'Turn an ordinary sleepover into an EXTRAORDINARY EXPERIENCE with our Sleepover Tent Package.', 'Turn an ordinary sleepover into an extraordinary experience with our Tent Sleepover Package. Our handcrafted sleepover tents and stunning decor make for the perfect slumber party, with over 15 themes to choose from for both boys and girls. Perfect for children ages 4-12.', '["Indoor","Sleepover"]', '["A-Frame tents with themed decor","Junior-size foam mattresses, sheets and blankets","Tray table and lantern for each tent","Decorative pillows, string lights and throw rug","Happy Birthday sign and themed garland","Eye mask for each guest to keep","Setup and take down included"]', '4-10 guests', 'Indoor space, minimum 12x12ft flat carpet or hard floor', 8000, 0, NULL, NULL, 1, 0, 1783613261421, 1783613261421);
