INSERT INTO packages (id, slug, name, tagline, description, tags, inclusions, capacity, space_requirement, starting_price_cents, price_is_placeholder, damage_deposit_cents, bundle_discount, featured, sort_order, created_at, updated_at) VALUES (8, 'pamper-party', 'Pamper Party', 'A mini at-home spa day for birthdays and girls'' nights.', 'Everything you need for the ultimate spa day! We set up all the essentials for DIY facials, manicures and pedicures. This package is recommended for guests 7+; younger guests may require assistance.', '["Indoor","Lounge"]', '["DIY Facial Station with vanity mirrors and facial bowls","DIY Mani/Pedi Station with foot tubs and nail polish bar","Spa robes and slippers for each guest","Face wipes, bath bombs and other take-home spa favors","Spa-themed decor and place settings","Setup and take down included"]', 'Recommended for ages 7+; up to 6 guests (extra guests welcome)', 'Indoor space, minimum 10x10ft', 49500, 0, NULL, NULL, 0, 7, 1783613261421, 1783613261421);
