INSERT INTO addon_categories (id, slug, name, tagline, description, hero_image_url, hero_image_alt, card_image_url, card_image_alt, sort_order) VALUES (2, 'activities-crafts', 'Activities & Crafts', 'What''s a celebration without activities? Let us take the planning off your plate.', 'What''s a celebration without activities? Let us take the planning off your plate. Choose from a variety of activity and craft stations designed to help keep your guests entertained. Whether you are looking for a bounce house or jewelry making station, we can help!', '/media/MAIN-ML-1.jpg', 'Activities & Crafts add-ons', '/media/Activities.jpg', 'Activities & Crafts add-ons preview', 1);
