INSERT INTO catalog_items (id, placement, addon_category_id, slug, name, price_cents, is_price_on_request, category_breadcrumb, image_url, additional_image_urls, description, details, pricing, sort_order) VALUES (9, 'add_on_category', 2, 'pillowcase-craft', 'Pillowcase Craft', 1500, 0, 'Hospitality > Party Favors', '/media/add-ons/pillowcase-craft.jpg', NULL, '["A hands-on craft station where guests decorate their own pillowcase to take home."]', NULL, '[{"label":"Purchase Price","value":"$15.00"}]', 1);
INSERT INTO addon_categories (id, slug, name, tagline, description, hero_image_url, hero_image_alt, card_image_url, card_image_alt, sort_order) VALUES (3, 'favors', 'Favors', 'From personalized tumblers to matching pajamas we''ve got you covered.', 'From personalized tumblers to matching pajamas we''ve got you covered. Send guests home with fun and personalized favors that they will use again and again.', '/media/MAIN-Canopy-Lounge-Copy.jpg', 'Favors add-ons', '/media/Favors.jpeg', 'Favors add-ons preview', 2);
